const items = $input.all();

  if (items.length === 1 && (items[0].json.noResults || items[0].json.noNewGrants)) {
    return items;
  }

  function extractDate(grant) {
    // Try closeDate first, then fallback fields
    const candidates = [
      grant.closeDate,
      grant.deadline,
      grant.dueDate,
      grant.due_date,
      grant.endDate,
      grant.end_date,
      grant.applicationDeadline,
      grant.application_deadline,
    ];

    for (const val of candidates) {
      if (!val || typeof val !== 'string') continue;
      const parsed = new Date(val);
      if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
        return parsed;
      }
    }

    // Try to find a date in the description
    if (grant.description) {
      const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
      if (match) {
        const parsed = new Date(match[0]);
        if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
          return parsed;
        }
      }
    }

    return null;
  }

  const withDeadline = [];
  const noDeadline = [];

  for (const item of items) {
    const date = extractDate(item.json);
    if (date) {
      item._sortDate = date;
      withDeadline.push(item);
    } else {
      noDeadline.push(item);
    }
  }

  // Soonest deadlines first
  withDeadline.sort((a, b) => a._sortDate - b._sortDate);

  const combined = [...withDeadline, ...noDeadline];
return combined.map(item => ({ json: item.json }));

// ============================================================
// Insert Into Central Grants (org-agnostic catalog)
// ============================================================
// Replaces the old per-org AI filter + insert pipeline. All scraped
// grants are dumped into public.central_grants. Dedupe: skip rows
// that already exist by (source, source_id) — or (source, source_url)
// when source_id is missing. No updates, no AI screening.
// ============================================================

const items = $input.all();
const DEDUP_BATCH = 500;
const INSERT_BATCH = 100;

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'REPLACE_ME_SUPABASE_SERVICE_KEY';
const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
};
const supaReadHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
};

// --- STEP 1: Normalize incoming grants ---
const rows = [];
for (const item of items) {
  const g = item.json.grant || item.json;
  if (g.empty || g.noResults) continue;
  const title = (g.title || '').trim();
  if (!title) continue;
  const source = (g.source || 'Grant Scanner').trim();
  const source_id = (g.oppNum || g.source_id || '').toString().trim() || null;
  const source_url = (g.link || g.source_url || '').toString().trim() || null;
  if (!source_id && !source_url) continue; // central_grants requires one

  // Parse deadline to YYYY-MM-DD or null
  let deadline = null;
  const raw = g.closeDate || g.deadline || '';
  if (raw && !['See listing', 'Not specified', 'Rolling', 'Ongoing'].includes(raw)) {
    const d = new Date(raw);
    if (!isNaN(d.getTime()) && d.getFullYear() > 2000) {
      deadline = d.toISOString().split('T')[0];
    }
  }

  // Skip already-expired grants. Null deadline = rolling/ongoing — keep.
  if (deadline) {
    const todayIso = new Date().toISOString().slice(0, 10);
    if (deadline < todayIso) continue;
  }

  rows.push({
    title: title,
    funder_name: g.agency || null,
    organization: null,
    amount: g.awardCeiling && g.awardCeiling > 0 ? String(g.awardCeiling) : null,
    deadline: deadline,
    description: g.description || '',
    eligibility: null,
    categories: g.category ? [g.category] : null,
    metadata: Object.assign({
      agency_code: g.agencyCode || null,
      open_date: g.openDate || null,
      award_floor: g.awardFloor || 0,
      award_ceiling: g.awardCeiling || 0,
      status: g.status || null,
    }, g.metadata || {}),
    source: source,
    source_id: source_id,
    source_url: source_url,
  });
}

if (rows.length === 0) {
  return [{ json: { message: 'No grants to insert', inserted: 0 } }];
}

// --- STEP 2: Dedupe against existing central_grants ---
// Group keys by source so we can query efficiently
const bySourceIds = {};   // source -> Set(source_id)
const bySourceUrls = {};  // source -> Set(source_url) [only when source_id null]
for (const r of rows) {
  if (r.source_id) {
    (bySourceIds[r.source] ||= new Set()).add(r.source_id);
  } else {
    (bySourceUrls[r.source] ||= new Set()).add(r.source_url);
  }
}

const existing = new Set(); // "source::key"
const enc = encodeURIComponent;
const quote = (s) => '"' + String(s).replace(/"/g, '\\"') + '"';

async function fetchExisting(source, column, values) {
  const arr = Array.from(values);
  for (let i = 0; i < arr.length; i += DEDUP_BATCH) {
    const chunk = arr.slice(i, i + DEDUP_BATCH);
    const inList = chunk.map(quote).join(',');
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: supabaseUrl + '/central_grants?source=eq.' + enc(source) +
             '&' + column + '=in.(' + inList + ')&select=' + column,
        headers: supaReadHeaders,
      });
      if (Array.isArray(resp)) {
        for (const row of resp) {
          if (row[column]) existing.add(source + '::' + row[column]);
        }
      }
    } catch (e) {}
  }
}

for (const [source, ids] of Object.entries(bySourceIds)) {
  await fetchExisting.call(this, source, 'source_id', ids);
}
for (const [source, urls] of Object.entries(bySourceUrls)) {
  await fetchExisting.call(this, source, 'source_url', urls);
}

// --- STEP 3: Filter to rows that don't exist yet ---
const seenInBatch = new Set();
const toInsert = [];
for (const r of rows) {
  const key = r.source + '::' + (r.source_id || r.source_url);
  if (existing.has(key)) continue;
  if (seenInBatch.has(key)) continue; // intra-batch dupe
  seenInBatch.add(key);
  toInsert.push(r);
}

if (toInsert.length === 0) {
  return [{ json: { message: 'All grants already in central_grants', scanned: rows.length, inserted: 0 } }];
}

// --- STEP 3.5: Enrich thin descriptions via sub-workflow ---
// Only fires for NEW grants (already deduped above) whose description is
// shorter than THIN_LIMIT. Runs in parallel slices to keep latency down.
// Any failure -> grant keeps its original description (never dropped).
const THIN_LIMIT = 200;
const ENRICH_CONCURRENCY = 10;
const ENRICH_URL = 'https://n8n.thebrownmine.com/webhook/enrich-grant-description';
const thinGrants = toInsert.filter(r => (r.description || '').length < THIN_LIMIT);
for (let i = 0; i < thinGrants.length; i += ENRICH_CONCURRENCY) {
  const slice = thinGrants.slice(i, i + ENRICH_CONCURRENCY);
  await Promise.all(slice.map(async (r) => {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: ENRICH_URL,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: r.title,
          funder_name: r.funder_name,
          source_url: r.source_url,
          description: r.description,
        }),
        json: true,
        timeout: 90000,
      });
      const next = (resp && resp.description) || '';
      if (next && next.length > (r.description || '').length) {
        r.description = next;
      }
    } catch (e) {}
  }));
}

// --- STEP 4: Batch insert ---
let inserted = 0;
for (let i = 0; i < toInsert.length; i += INSERT_BATCH) {
  const batch = toInsert.slice(i, i + INSERT_BATCH);
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/central_grants',
      headers: Object.assign({}, supaHeaders, { 'Prefer': 'return=minimal,resolution=ignore-duplicates' }),
      body: JSON.stringify(batch),
    });
    inserted += batch.length;
  } catch (e) {
    // Fall back to per-row on batch failure
    for (const row of batch) {
      try {
        await this.helpers.httpRequest({
          method: 'POST',
          url: supabaseUrl + '/central_grants',
          headers: Object.assign({}, supaHeaders, { 'Prefer': 'return=minimal,resolution=ignore-duplicates' }),
          body: JSON.stringify(row),
        });
        inserted++;
      } catch (e2) {}
    }
  }
}

return [{ json: { success: true, scanned: rows.length, inserted: inserted, skippedExisting: rows.length - toInsert.length } }];

// Status callback helper: only sends status if callback_url exists (new org registration)
