  return items;
}

if (!callbackUrl || !orgId) return items;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: callbackUrl,
    headers: {
      'Content-Type': 'application/json',
      'x-webhook-secret': 'REPLACE_ME_WEBHOOK_SECRET'
    },
